import {useEffect, useRef, useState} from 'react';
import BtnReturn from 'app/components/shared/BtnReturn';
import Title from 'app/components/shared/Title';
import manualSensorDataStore from 'app/stores/sensors/manualSensorDataStore';
import sensorStore from 'app/stores/sensors/sensorStore';
import AddDataForm from './AddDataForm';
import EditManualSensorData from '../editManualSensorData/EditManualSensorData';
import router from 'app/utils/router';
import dataStore from 'app/stores/sensors/dataStore';
import DataTypeIcon from 'app/components/shared/DataTypeIcon';
import {useStore} from 'app/hooks/store';
import sidebarStore from 'app/stores/sidebarStore';
import buildingStore from 'app/stores/buildings/buildingStore';
import appStore from 'app/stores/appStore';
import GenericModal from 'app/components/shared/GenericModal';
import dayjs from 'dayjs';
import XLSX from 'xlsx';
import Button from 'app/components/sharedV2/Button';

const {i18n} = __;

function ManualSensorDataForm({sensorId, buildingId}) {
  const today = new Date();
  const store = manualSensorDataStore;
  const [sensor, setSensor] = useState({});
  const [sensorData, setSensorData] = useState([]);
  const [buildingsTree, setBuildingsTree] = useState(buildingStore.getState().buildingsTree);
  const [year, setYear] = useState(today.getFullYear());
  const [fileData, setFileData] = useState(null);

  useEffect(() => {
    sensorStore.fetch(sensorId).then((sensor) => {
      setSensor(sensor);
    });
  }, []);

  useStore(sensorStore, () => {
    setSensor(sensorStore.getState().sensor);
  });

  useStore(buildingStore, () => {
    setBuildingsTree(buildingStore.getState().buildingsTree);
  });

  useEffect(() => {
    window.scrollTo(0, 0);

    appStore.setAppTitle(i18n.t('ManualSensorDataForm.appTitle'));
    sidebarStore.displayBuildingsList({
      showSensors: true,
      showOnlyManualSensors: true,
      onClickSensor: (sensor) => {
        setSensor(sensor);
        router.goTo('sensors.manageManualSensorData', {
          id: sensor.id,
          buildingId: sensor.buildingId,
        });
      },
    });
  }, []);

  const redirectToVisualisation = (e) => {
    e.preventDefault();
    const sensor = sensorStore.getState().sensors.find((s) => s.id == sensorId);
    if (sensor) {
      const {year, month} = store.getState();
      const dateBegin = moment().subtract(7, 'days');
      const dateEnd = moment();

      dataStore
        .removeAllDataToDisplay()
        .then(() => {
          return dataStore.updateGeneralDates({dateBegin, dateEnd}).then(() => {
            return dataStore.addDatumToDisplay({sensor}).then(() => router.goTo('visualization'));
          });
        })
        .catch(__.debugErr);
    }
  };

  const getSensorPath = () => {
    if (!sensor) return;
    let path = '';
    let building = buildingsTree.find((b) => b.id === buildingId);
    let parentId = sensor.buildingId;
    while (parentId) {
      building = buildingStore.getState().buildings.find((b) => b.id === parentId);
      if (building) {
        parentId = building.parentId;
        path = building.name + ' > ' + path;
      } else {
        path = path + sensor.name;
        break;
      }
    }
    if (!parentId) path = path + sensor.name;
    return path;
  };

  const handleButtonClick = () => {
    if (fileInputRef.current) {
      fileInputRef.current.click();
    }
  };

  const getPeriod = (data) => {
    if (!data.length) return {begin: null, end: null};
    let begin = data[0].rec_date;
    let end = data[0].rec_date;
    data.forEach((d) => {
      if (d.rec_date < begin) {
        begin = d.rec_date;
      }
      if (d.rec_date > end) {
        end = d.rec_date;
      }
    });
    return {begin, end};
  };

  const fileInputRef = useRef(null);
  const handleFileInputChange = (e) => {
    const file = e.target.files[0];

    const fileName = file.name;
    const fileExtension = fileName.split('.').pop().toLowerCase();

    if (fileExtension !== 'csv' && fileExtension !== 'xlsx') {
      __.ui.notifyError(i18n.t('ManualSensorDataForm.invalidFileExtension'));
      return;
    }

    const reader = new FileReader();

    reader.onload = (event) => {
      let csvData = '';
      const data = new Uint8Array(event.target.result);

      if (fileExtension === 'xlsx') {
        const workbook = XLSX.read(data, {type: 'array'});
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        csvData = XLSX.utils.sheet_to_csv(worksheet);
      } else if (fileExtension === 'csv') {
        csvData = event.target.result.replace(/"/g, '');
      }
      csvData = csvData.split('\n');
      let splitData = csvData.map((str) => str.split(','));
      const result = [];
      for (let i = 1; i < splitData.length; i++) {
        const row = splitData[i];
        for (let j = 1; j < row.length; j++) {
          let date = splitData[0][j];
          let dt = dayjs(date, __.app.dateUiFormat);
          const rec_date = dayjs(splitData[0][j], __.app.dateUiFormat).format(__.app.dateApiFormat);
          if (dayjs(rec_date).isValid()) {
            const obj = {
              rec_date: rec_date,
              rec_time: '12:00',
              index: splitData[1][j],
              sensor_code: sensor.code,
            };
            result.push(obj);
          }
        }
      }
      store.fetchAll(sensorId, year, 1).then((datas) => {
        datas.data.forEach((data) => {
          result.push({
            rec_date: data.recDate,
            rec_time: dayjs(data.recTime, 'HH:mm:ss').format('HH:mm'),
            index: data.index,
          });
        });
        const {begin, end} = getPeriod(result);
        const sensorInfos = {
          sensor_id: sensorId,
          date_begin: dayjs(`${year}-01-01`).format('YYYY-MM-DD'),
          date_end: dayjs(`${year}-12-31`).format('YYYY-MM-DD'),
          datas: result,
        };

        store.update(sensorInfos, {}, {shouldThrow: true}).then(() => {
          store.fetchAll(sensorId, year, 1);
        });
      });
    };

    if (fileExtension === 'xlsx') {
      reader.readAsArrayBuffer(file);
    } else if (fileExtension === 'csv') {
      reader.readAsText(file);
    }
  };

  const renderSensorName = () => {
    let path = getSensorPath();
    return (
      <div className='d-f-between'>
        <div className='d-f-a text-15'>
          {sensor && sensor.dataTypeId ? <DataTypeIcon id={sensor.dataTypeId} /> : null}
          <span className='m-l-1'>{sensor ? path : null}</span>
          {sensor && sensor.dataTypeId && sensor.dataTypeId === 4 ? (
            <div
              className='cursor-pointer fa fa-question-circle-o m-l-05'
              title={i18n.t('ManualSensorDataForm.gasInfo')}
            />
          ) : null}
        </div>
        <div className='f f-gap-10'>
          <Button
            btnType='gray'
            onClick={(e) => redirectToVisualisation(e)}
            style={{height: 'fit-content'}}
          >
            {i18n.t('ManualSensorDataForm.visualisationBtn')}
          </Button>
          <input
            type='file'
            accept='.csv, .xlsx'
            style={{display: 'none'}}
            ref={fileInputRef}
            onChange={handleFileInputChange}
          />
          <div className='f-column f-gap-4'>
            <Button
              btnType='gray'
              onClick={handleButtonClick}
            >
              {i18n.t('ManualSensorDataForm.uploadBtn')}
            </Button>
            <Button
              btnType='gray'
              onClick={() => {
                _.toXLSX({
                  data: [{'': 'Index', '01/01/2021': 123, '02/01/2021': 456, '03/01/2021': 789}],
                  fileName: 'egreen_conso_export',
                });
              }}
            >
              {i18n.t('ManualSensorDataForm.uploadPreview')}
            </Button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <section id='content'>
      <div className='container'>
        <BtnReturn />
        <div className='card padding-5 fix-height'>
          <Title
            title={i18n.t('ManualSensorDataForm.creationTitle')}
            level={1}
          />
          <div className='p-h-1'>{renderSensorName()}</div>
          <AddDataForm
            sensorId={sensorId}
            buildingId={buildingId}
            onSubmitted={() => {
              store.fetchAll(sensorId, year, 1);
            }}
            sensor={sensor}
          />
          <EditManualSensorData
            sensorId={sensorId}
            year={year}
            onYearChange={(year) => {
              setYear(year);
              store.fetchAll(sensorId, year, 1);
            }}
          />
        </div>
      </div>
    </section>
  );
}

export default ManualSensorDataForm;
